# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# Initialize Web3
w3 = Web3()

# In-memory storage for nonces (use Redis/database in production)
nonces = {}
authenticated_sessions = {}

# Configuration
NONCE_EXPIRY = 300  # 5 minutes
SESSION_EXPIRY = 86400  # 24 hours
JWT_EXPIRY = 86400  # 24 hours


def generate_nonce():
    """Generate a random nonce for signature verification"""
    return secrets.token_hex(16)


def cleanup_expired_nonces():
    """Remove expired nonces"""
    current_time = time.time()
    expired = [addr for addr, data in nonces.items() 
               if current_time - data['timestamp'] > NONCE_EXPIRY]
    for addr in expired:
        del nonces[addr]


def cleanup_expired_sessions():
    """Remove expired sessions"""
    current_time = time.time()
    expired = [token for token, data in authenticated_sessions.items() 
               if current_time - data['timestamp'] > SESSION_EXPIRY]
    for token in expired:
        del authenticated_sessions[token]


def verify_signature(message, signature, expected_address):
    """
    Verify an Ethereum signature and check if it matches the expected address
    
    Args:
        message: The original message that was signed
        signature: The signature hex string
        expected_address: The Ethereum address that should have signed the message
        
    Returns:
        bool: True if signature is valid and matches expected address
    """
    try:
        # Encode the message
        message_hash = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(
            message_hash, 
            signature=signature
        )
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False


def create_jwt_token(address):
    """Create a JWT token for authenticated user"""
    payload = {
        'address': address,
        'exp': datetime.utcnow() + timedelta(seconds=JWT_EXPIRY),
        'iat': datetime.utcnow()
    }
    token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
    return token


def verify_jwt_token(token):
    """Verify a JWT token and return the address"""
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload['address']
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


@app.route('/api/auth/nonce', methods=['POST'])
def request_nonce():
    """
    Request a nonce for a given Ethereum address
    
    Expected JSON:
    {
        "address": "0x..."
    }
    """
    cleanup_expired_nonces()
    
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate Ethereum address format
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address to checksum format
    address = w3.to_checksum_address(address)
    
    # Generate and store nonce
    nonce = generate_nonce()
    nonces[address] = {
        'nonce': nonce,
        'timestamp': time.time()
    }
    
    return jsonify({
        'nonce': nonce,
        'message': f'Sign this message to authenticate with nonce: {nonce}'
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature_endpoint():
    """
    Verify a signed message and authenticate the user
    
    Expected JSON:
    {
        "address": "0x...",
        "signature": "0x...",
        "message": "Sign this message to authenticate with nonce: ..."
    }
    """
    cleanup_expired_nonces()
    cleanup_expired_sessions()
    
    data = request.get_json()
    
    if not data or not all(k in data for k in ['address', 'signature', 'message']):
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    # Validate Ethereum address format
    if not w3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address
    address = w3.to_checksum_address(address)
    
    # Check if nonce exists for this address
    if address not in nonces:
        return jsonify({'error': 'No nonce found for this address. Request a nonce first.'}), 400
    
    stored_nonce = nonces[address]['nonce']
    
    # Verify the nonce is in the message
    if stored_nonce not in message:
        return jsonify({'error': 'Invalid message or nonce'}), 400
    
    # Verify the signature
    if not verify_signature(message, signature, address):
        return jsonify({'error': 'Invalid signature'}), 401
    
    # Remove used nonce
    del nonces[address]
    
    # Create JWT token
    token = create_jwt_token(address)
    
    # Store session
    session_token = secrets.token_hex(32)
    authenticated_sessions[session_token] = {
        'address': address,
        'timestamp': time.time()
    }
    
    return jsonify({
        'success': True,
        'token': token,
        'session_token': session_token,
        'address': address,
        'message': 'Authentication successful'
    }), 200


@app.route('/api/auth/validate', methods=['POST'])
def validate_token():
    """
    Validate a JWT token
    
    Expected JSON:
    {
        "token": "jwt_token_here"
    }
    
    Or Authorization header:
    Authorization: Bearer <token>
    """
    data = request.get_json() or {}
    
    # Try to get token from JSON body or Authorization header
    token = data.get('token')
    if not token:
        auth_header = request.headers.get('Authorization')
        if auth_header and auth_header.startswith('Bearer '):
            token = auth_header.split(' ')[1]
    
    if not token:
        return jsonify({'error': 'Token is required'}), 400
    
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'valid': True,
        'address': address
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
def logout():
    """
    Logout and invalidate session
    
    Expected JSON:
    {
        "session_token": "session_token_here"
    }
    """
    data = request.get_json()
    
    if not data or 'session_token' not in data:
        return jsonify({'error': 'Session token is required'}), 400
    
    session_token = data['session_token']
    
    if session_token in authenticated_sessions:
        del authenticated_sessions[session_token]
    
    return jsonify({
        'success': True,
        'message': 'Logged out successfully'
    }), 200


@app.route('/api/protected', methods=['GET'])
def protected_route():
    """
    Example protected route that requires authentication
    """
    auth_header = request.headers.get('Authorization')
    
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({'error': 'Authorization header required'}), 401
    
    token = auth_header.split(' ')[1]
    address = verify_jwt_token(token)
    
    if not address:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'address': address,
        'data': 'This is protected data'
    }), 200


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({
        'status': 'healthy',
        'service': 'Web3 Authentication Service',
        'active_nonces': len(nonces),
        'active_sessions': len(authenticated_sessions)
    }), 200


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)